"use client";
import React, { useState, useEffect } from "react";
import { Button, Card, Input, Textarea } from "@nextui-org/react";
import { Clapperboard, CloudUpload, Plus, Trash2 } from "lucide-react";

export default function App() {
  const [mounted, setMounted] = useState(false);
  const [view, setView] = useState<"landing" | "studio">("landing");
  const [scenes, setScenes] = useState([{ id: "1", title: "Scene 01", description: "" }]);

  useEffect(() => { setMounted(true); }, []);

  const saveToCloud = async () => {
    try {
      const res = await fetch("/api/project", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name: "MAIN_PROJECT", scenes }),
      });
      if (res.ok) alert("Synced to MongoDB!");
    } catch (e) { alert("Sync failed."); }
  };

  if (!mounted) return null;

  if (view === "landing") {
    return (
      <div className="h-screen w-full bg-black flex flex-col items-center justify-center text-center p-6">
        <Clapperboard className="w-20 h-20 text-blue-500 mb-6" />
        <h1 className="text-6xl font-bold text-white mb-4">DIRECTOR'S BOARD</h1>
        <Button size="lg" color="primary" onClick={() => setView("studio")}>INITIALIZE STUDIO</Button>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-black text-white flex">
      <div className="w-64 border-r border-white/10 p-6 flex flex-col gap-4">
        <h2 className="font-bold text-xl tracking-tighter uppercase">Studio_v1</h2>
        <Button startContent={<CloudUpload size={18}/>} color="primary" variant="flat" onClick={saveToCloud}>Sync Cloud</Button>
      </div>
      <main className="flex-1 p-10 overflow-y-auto">
        <div className="flex justify-between items-center mb-10">
          <h1 className="text-3xl font-bold tracking-widest uppercase">Project_Manifesto</h1>
          <Button startContent={<Plus size={18}/>} onClick={() => setScenes([...scenes, { id: Math.random().toString(), title: "", description: "" }])}>Add Frame</Button>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {scenes.map((s, i) => (
            <Card key={s.id} className="p-6 bg-zinc-900 border-white/5">
              <div className="flex justify-between mb-4">
                <span className="text-xs text-blue-500 font-mono">FRAME_0{i+1}</span>
                <Button isIconOnly size="sm" variant="light" onClick={() => setScenes(scenes.filter(x => x.id !== s.id))}><Trash2 size={14} className="text-red-500"/></Button>
              </div>
              <Input label="Title" variant="underlined" className="mb-4 text-white" />
              <Textarea label="Notes" variant="bordered" className="text-white" />
            </Card>
          ))}
        </div>
      </main>
    </div>
  );
}

import mongoose from "mongoose";
const MONGODB_URI = process.env.MONGODB_URI;
if (!MONGODB_URI) throw new Error("Missing MONGODB_URI");
let cached = (global as any).mongoose || { conn: null, promise: null };
export default async function connectDB() {
  if (cached.conn) return cached.conn;
  if (!cached.promise) {
    cached.promise = mongoose.connect(MONGODB_URI!).then((m) => m);
  }
  cached.conn = await cached.promise;
  return cached.conn;
}

import mongoose, { Schema, model, models } from "mongoose";
const ProjectSchema = new Schema({
  name: { type: String, required: true },
  scenes: { type: Array, default: [] },
  updatedAt: { type: Date, default: Date.now },
});
export const Project = models.Project || model("Project", ProjectSchema);
